const resumeId = $('Code - Valida id e binário').first().json.id;

const raw =
  $input.first().json.output ||
  $input.first().json.response?.generations?.[0]?.[0]?.text ||
  $input.first().json.message?.content ||
  $input.first().json.choices?.[0]?.message?.content;

if (!raw) throw new Error('Resposta vazia: ' + JSON.stringify($input.first().json));

// Remove <think> e markdown
let stripped = typeof raw === 'string'
  ? raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim()
  : raw;
stripped = stripped.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(stripped);
} catch(e) {
  const match = stripped.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('JSON inválido: ' + stripped.substring(0, 300));
  parsed = JSON.parse(match[0]);
}

const originalText = $('Extract from File - PDF to Text').first().json.text || '';

return [{
  json: {
    resume_id:            resumeId,
    employability_score:  parsed.employability_score,
    ats_rejection_chance: parsed.ats_rejection_chance,
    hook_message:         parsed.hook_message,
    brutal_roast:         parsed.brutal_roast,
    red_flags:            JSON.stringify(parsed.red_flags   || []),
    improvement_tips:     JSON.stringify(parsed.improvement_tips || []),
    rewritten_summary:    parsed.rewritten_summary,
    questions:            JSON.stringify(parsed.questions   || []),
    original_text:        originalText,
    status:               'analyzed',
    created_at:           new Date().toISOString()
  }
}];
